          begin
            if (encdec)
              dec_next = 1'b1;
            else
              enc_next = 1'b1;

            if (muxed_ready)
              begin
                ready_new         = 1'b1;
                ready_we          = 1'b1;
                result_valid_new  = 1'b1;
                result_valid_we   = 1'b1;
                aes_core_ctrl_new = CTRL_IDLE;
                aes_core_ctrl_we  = 1'b1;
              end
          end

        default:
          begin
          end
      endcase // case (aes_core_ctrl_reg)
    end // aes_core_ctrl

